INSERT INTO `survey_categories` VALUES (1,'608287f2-7222-4c7f-ba88-50277460d2fe',1,'Reliability (Keandalan)','Kemampuan dosen dalam melaksanakan pembelajaran secara konsisten, akurat, dan sesuai dengan perencanaan.',1,'2026-05-21 23:25:44','2026-05-25 02:25:03',NULL,NULL),(2,'69e19e83-bdd2-43b3-9442-8f0f82c4c7ba',1,'Responsiveness (Daya Tanggap)','Kesediaan dan kecepatan dosen dalam membantu mahasiswa dan merespons kebutuhan pembelajaran.',2,'2026-05-21 23:25:44','2026-05-25 02:25:03',NULL,NULL),(3,'5b7c6737-79c3-40ef-a449-120fc43b0be3',1,'Assurance (Jaminan)','Pengetahuan, sikap profesional, dan kemampuan dosen dalam menumbuhkan rasa percaya dan aman pada mahasiswa.',3,'2026-05-21 23:25:44','2026-05-25 04:48:53',NULL,NULL),(4,'0e386c96-df46-4385-b380-9e0a3be1442f',1,'Empathy (Empati)','Perhatian, kepedulian, dan pemahaman dosen terhadap kebutuhan serta kondisi mahasiswa.',4,'2026-05-21 23:25:44','2026-05-25 02:25:03',NULL,NULL),(5,'997e4ba8-8e84-40fc-8b18-85ffbbf3e3bb',1,'Tangible (Bukti Fisik)','Penampilan fisik, sarana prasarana, dan media pembelajaran yang digunakan dosen.',5,'2026-05-21 23:25:44','2026-05-25 02:25:03',NULL,NULL),(6,'aaeb2203-5ee1-4816-bca0-0c4d7dde67a0',2,'Reliability (Keandalan)','Kemampuan layanan administrasi akademik dalam memberikan pelayanan secara tepat, konsisten, dan dapat diandalkan.',1,'2026-05-21 23:25:44','2026-05-25 02:25:03',NULL,NULL),(7,'d91f754a-8a58-47f0-bbe9-93e999dc9e9b',2,'Responsiveness (Daya Tanggap)','Kesediaan dan kecepatan petugas dalam mmbantu mahasiswa.',2,'2026-05-21 23:25:44','2026-05-25 02:25:03',NULL,NULL),(8,'278a9354-830c-486b-bf2b-23ec42be1a24',2,'Assurance (Jaminan)','Pengetahuan, kesopanan, dan kemampuan petugas dalam memberikan rasa percaya.',3,'2026-05-21 23:25:44','2026-05-25 02:25:03',NULL,NULL),(9,'f7a64906-6226-4947-9071-8489d67e7db5',2,'Empathy (Empati)','Perhatian dan kepedulian petugas terhadap kebutuhan mahasiswa.',4,'2026-05-21 23:25:44','2026-05-25 02:25:03',NULL,NULL),(10,'a544e1d0-5437-4693-b9